function solve(n: number, edges: number[][], k: number): number {
    let maxTime = 0;
    for (const [u, v, t] of edges) {
        if (t > maxTime) maxTime = t;
    }

    let low = 0, high = maxTime;
    let answer = maxTime;

    while (low <= high) {
        const mid = Math.floor((low + high) / 2);
        const adj: number[][] = Array.from({ length: n }, () => []);

        for (const [u, v, t] of edges) {
            if (t > mid) {
                adj[u].push(v);
                adj[v].push(u);
            }
        }

        const visited = new Array<boolean>(n).fill(false);
        let components = 0;

        for (let i = 0; i < n; i++) {
            if (!visited[i]) {
                components++;
                const queue: number[] = [i];
                visited[i] = true;

                while (queue.length > 0) {
                    const node = queue.shift()!;
                    for (const neighbor of adj[node]) {
                        if (!visited[neighbor]) {
                            visited[neighbor] = true;
                            queue.push(neighbor);
                        }
                    }
                }
            }
        }

        if (components >= k) {
            answer = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    return answer;
}

