import scala.collection.mutable.Queue

def solve(n: Long, edges: Array[Array[Long]], k: Long): Long = {
    val maxTime = if (edges.isEmpty) 0 else edges.map(edge => edge(2)).max
    var low = 0L
    var high = maxTime
    var answer = maxTime
    while (low <= high) {
        val mid = (low + high) / 2
        val adj = Array.fill(n.toInt)(Array.empty[Long])
        for (edge <- edges) {
            val u = edge(0)
            val v = edge(1)
            val t = edge(2)
            if (t > mid) {
                adj(u.toInt).append(v)
                adj(v.toInt).append(u)
            }
        }
        val visited = Array.fill(n.toInt)(false)
        var components = 0
        for (i <- 0 until n.toInt) {
            if (!visited(i)) {
                components += 1
                val queue = Queue[Int](i)
                visited(i) = true
