import scala.collection.mutable.ListBuffer
import scala.collection.mutable.Queue

def solve(n: Long, edges: Array[Array[Long]], k: Long): Long = {
  val maxTime = if (edges.isEmpty) 0L else edges.map(_.last).max
  var low = 0L
  var high = maxTime
  var answer = maxTime

  while (low <= high) {
    val mid = (low + high) / 2
    val adj = Array.fill(n.toInt)(ListBuffer[Int]())
    for (edge <- edges) {
      val u = edge(0).toInt
      val v = edge(1).toInt
      val t = edge(2)
      if (t > mid) {
        adj(u) += v
        adj(v) += u
      }
    }

    val visited = Array.fill(n.toInt)(false)
    var components = 0
    for (i <- 0 until n.toInt) {
      if (!visited(i)) {
        components += 1
        val queue = Queue[Int]()
        queue += i
        visited(i) = true
        while (queue.nonEmpty) {
          val node = queue.dequeue
          for (neighbor <- adj(node)) {
            if (!visited(neighbor)) {
              visited(neighbor) = true
              queue += neighbor
            }
          }
        }
      }
    }

    if (components >= k) {
      answer = mid
      high = mid - 1
    } else {
      low = mid + 1
    }
  }

  answer
}
